// NODE: Parse Video Pipeline Message
// Routes incoming Telegram messages to the correct handler:
//   - #body scenario_name clip_index [section]  脙垄脗聠脗聮 body clip upload
//   - #hook scenario_name                       脙垄脗聠脗聮 manual hook clip upload
//   - #outro scenario_name label                脙垄脗聠脗聮 manual outro clip upload
//   - /produce scenario_name [template]         脙垄脗聠脗聮 trigger video production
//   - /done                                     脙垄脗聠脗聮 finish recording, start production
//   - video with no caption (during recording)  脙垄脗聠脗聮 auto body clip
//   - anything else                             脙垄脗聠脗聮 ignored
// Mode: Run Once for All Items
//
// WIRING: Telegram Trigger (message) 脙垄脗聠脗聮 this Code node 脙垄脗聠脗聮 Switch node (Route Message)
// Switch outputs: body_clip | hook_clip | outro_clip | produce | done_recording | auto_body_clip | unknown

const update = $input.first().json;
const message = update.message || update;
const text = (message.caption || message.text || '').trim();
const chatId = message.chat?.id || '';

const hasVideo = !!(message.video || message.document);
const video = message.video || message.document || {};

// 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙 #body scenario_name clip_index [section] 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙
const bodyMatch = text.match(/#body\s+(\S+)\s+(\d+)(?:\s+(\S+))?/i);
if (hasVideo && bodyMatch) {
  return [{
    json: {
      messageType: 'body_clip',
      scenarioName: bodyMatch[1],
      clipIndex: parseInt(bodyMatch[2], 10),
      section: bodyMatch[3] || '',
      fileId: video.file_id,
      fileSize: video.file_size || 0,
      duration: video.duration || 0,
      chatId,
    }
  }];
}

// 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙 #hook scenario_name 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙
const hookMatch = text.match(/#hook\s+(\S+)/i);
if (hasVideo && hookMatch) {
  return [{
    json: {
      messageType: 'hook_clip',
      scenarioName: hookMatch[1],
      fileId: video.file_id,
      fileSize: video.file_size || 0,
      duration: video.duration || 0,
      chatId,
    }
  }];
}

// 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙 #outro scenario_name label 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙
const outroMatch = text.match(/#outro\s+(\S+)\s+(\S+)/i);
if (hasVideo && outroMatch) {
  return [{
    json: {
      messageType: 'outro_clip',
      scenarioName: outroMatch[1],
      label: outroMatch[2],
      fileId: video.file_id,
      fileSize: video.file_size || 0,
      duration: video.duration || 0,
      chatId,
    }
  }];
}

// 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙 /produce [scenario_name] 脙垄脗聙脗聰 no args = next ready scenario 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙
const produceMatch = text.match(/^\/produce(?:\s+(\S+))?$/i);
if (produceMatch) {
  return [{
    json: {
      messageType: 'produce',
      scenarioName: produceMatch[1] || '',
      chatId,
    }
  }];
}

// 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙 Access workflow static data (shared recording state) 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙
const staticData = $getWorkflowStaticData('global');

// 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙 /done 脙垄脗聙脗聰 finish recording 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙
if (text.match(/^\/done$/i)) {
  const activeRec = staticData.activeRecording;
  return [{
