}

// 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙 Video with no recognized command during active recording 脙垄脗聠脗聮 auto body clip 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙
if (hasVideo && staticData.activeRecording) {
