// 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙 retry helper 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙
async function withRetry(fn, retries = MAX_RETRIES) {
  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      return await fn();
    } catch (err) {
      if (attempt === retries) throw err;
      await new Promise(r => setTimeout(r, RETRY_DELAY_MS));
    }
  }
}

// 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙 Telegram file download helper (with retry) 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙
async function downloadTgFile(fileId, outputPath) {
  return withRetry(async () => {
    const getFileRes = await fetch('https://api.telegram.org/bot' + BOT_TOKEN + '/getFile?file_id=' + fileId);
    const getFileData = await getFileRes.json();
    const filePath = getFileData.result?.file_path;
    if (!filePath) throw new Error('getFile failed for ' + fileId);
    const downloadUrl = 'https://api.telegram.org/file/bot' + BOT_TOKEN + '/' + filePath;
    const res = await fetch(downloadUrl);
    if (!res.ok) throw new Error('Download failed: ' + res.status);
    const buffer = Buffer.from(await res.arrayBuffer());
    fs.writeFileSync(outputPath, buffer);
    return outputPath;
  });
}

// 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙 URL download helper (with retry) 脙垄脗聰脗聙脙垄脗聰脗聙脙垄脗聰脗聙
async function downloadUrl(url, outputPath) {
  return withRetry(async () => {
    const res = await fetch(url);
    if (!res.ok) throw new Error('URL download failed: ' + res.status);
    const buffer = Buffer.from(await res.arrayBuffer());
    fs.writeFileSync(outputPath, buffer);
    return outputPath;
  });
}

